    <linearGradient id="g" x1="0%" y1="0%" x2="100%" y2="0%">
      <stop offset="0%" stop-color="#0d1a2d" stop-opacity="0.8"/>
      <stop offset="50%" stop-color="#1a2e4a" stop-opacity="0.9"/>
